def configure_gpu():
    """Configure GPU settings for optimal performance."""
    print("TensorFlow version:", tf.__version__)
    print("GPU Available:", tf.config.list_physical_devices('GPU'))
    print("Built with CUDA:", tf.test.is_built_with_cuda())

    gpus = tf.config.list_physical_devices('GPU')
    if gpus:
        try:
            for gpu in gpus:
                tf.config.experimental.set_memory_growth(gpu, True)
            print(f"âœ“ GPU memory growth enabled for {len(gpus)} GPU(s)")

            policy = mixed_precision.Policy('mixed_float16')
            mixed_precision.set_global_policy(policy)
            print(f"âœ“ Mixed precision enabled: {policy.name}")
        except RuntimeError as e:
            print(f"GPU configuration error: {e}")
    else:
        print("âš  No GPU detected - training will use CPU")

configure_gpu()

def plot_health_index_summary(component: str, client: str = config.CLIENT): """Plot health index summary for a component.""" try: # Load unit-level health index hi_path = config.BASE_DATA_PATH / f"telemetry/golden/{client}/{component}_health_index_unit.parquet" hi_df = pd.read_parquet(hi_path)
# Create figure fig, axes = plt.subplots(2, 2, figsize=(15, 10)) fig.suptitle(f'Health Index Summary: {component}', fontsize=16, fontweight='bold')
# 1. Health index distribution axes[0, 0].hist(hi_df['health_index'], bins=30, edgecolor='black', alpha=0.7) axes[0, 0].axvline(hi_df['health_index'].mean(), color='red', linestyle='--', label=f'Mean: {hi_df["health_index"].mean():.3f}') axes[0, 0].set_xlabel('Health Index') axes[0, 0].set_ylabel('Frequency') axes[0, 0].set_title('Health Index Distribution') axes[0, 0].legend() axes[0, 0].grid(alpha=0.3)
# 2. Health index by unit hi_df_sorted = hi_df.sort_values('health_index') axes[0, 1].barh(range(len(hi_df_sorted)), hi_df_sorted['health_index']) axes[0, 1].set_yticks(range(len(hi_df_sorted))) axes[0, 1].set_yticklabels(hi_df_sorted[config.UNIT_COL], fontsize=8) axes[0, 1].set_xlabel('Health Index') axes[0, 1].set_title('Health Index by Unit') axes[0, 1].grid(alpha=0.3, axis='x')
# 3. Reconstruction error vs health index axes[1, 0].scatter(hi_df['reconstruction_error'], hi_df['health_index'], alpha=0.6) axes[1, 0].set_xlabel('Reconstruction Error') axes[1, 0].set_ylabel('Health Index') axes[1, 0].set_title('Reconstruction Error vs Health Index') axes[1, 0].grid(alpha=0.3)
# 4. Summary statistics axes[1, 1].axis('off') summary_text = f""" Summary Statistics {'='*40}
Number of Units: {len(hi_df)}
Health Index: Mean: {hi_df['health_index'].mean():.4f} Median: {hi_df['health_index'].median():.4f} Std: {hi_df['health_index'].std():.4f} Min: {hi_df['health_index'].min():.4f} Max: {hi_df['health_index'].max():.4f}
Reconstruction Error: Mean: {hi_df['reconstruction_error'].mean():.4f} Median: {hi_df['reconstruction_error'].median():.4f} Std: {hi_df['reconstruction_error'].std():.4f}
Total Records: {hi_df['n_records'].sum():,} """ axes[1, 1].text(0.1, 0.5, summary_text, fontsize=11, family='monospace', verticalalignment='center')
plt.tight_layout() plt.show()
return hi_df
except FileNotFoundError: print(f"Health index file not found for component: {component}") print("Run the pipeline first to generate results.") return None
# Example: Visualize results for a component if component_example in component_mapping['components']: hi_results = plot_health_index_summary(component_example, config.CLIENT)
